const express = require('express');
const app = express();
const port = 3000;

// Mock database for user profiles
const usersDb = [
  { id: 1, username: 'johndoe', email: 'john.doe@example.com', bio: 'Software Engineer', location: 'New York' },
  { id: 2, username: 'janesmith', email: 'jane.smith@example.com', bio: 'Product Manager', location: 'San Francisco' },
  { id: 3, username: 'petermartin', email: 'peter.martin@example.com', bio: 'UX Designer', location: 'London' }
];

// Middleware to simulate authentication and attach req.user
// In a real application, this would come from an actual auth strategy (JWT, OAuth, etc.)
app.use((req, res, next) => {
  // For demonstration, let's assume user with ID 1 is always authenticated
  req.user = { id: 1, username: 'johndoe', role: 'user' };
  next();
});

// GET /users/:id/profile - Returns user profile information
app.get('/users/:id/profile', (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId)) {
    return res.status(400).json({ message: 'Invalid user ID provided.' });
  }

  const userProfile = usersDb.find(user => user.id === userId);

  if (!userProfile) {
    return res.status(404).json({ message: 'User profile not found.' });
  }

  // In a real app, you might filter sensitive information before sending
  const { id, username, email, bio, location } = userProfile;
  res.json({ id, username, email, bio, location });
});

app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});

